import React, { useEffect, useRef } from 'react';
import { Button } from '../Button/Button';

interface ModalProps {
  open: boolean;
  onClose: () => void;
  title?: string;
  children: React.ReactNode;
  footer?: React.ReactNode;
}

export const Modal: React.FC<ModalProps> = ({ open, onClose, title, children, footer }) => {
  const overlayRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    if (open) document.addEventListener('keydown', handleEsc);
    return () => document.removeEventListener('keydown', handleEsc);
  }, [open, onClose]);

  if (!open) return null;

  return (
    <div
      ref={overlayRef}
      onClick={(e) => { if (e.target === overlayRef.current) onClose(); }}
      style={{
        position: 'fixed', inset: 0, zIndex: 1000,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        backgroundColor: 'rgba(0,0,0,0.5)',
      }}
    >
      <div style={{
        background: '#fff', borderRadius: 'var(--radius-lg)',
        boxShadow: 'var(--shadow-lg)', maxWidth: 560, width: '90%', maxHeight: '90vh',
        display: 'flex', flexDirection: 'column',
      }}>
        {title && (
          <div style={{ padding: 'var(--spacing-4)', borderBottom: '1px solid var(--color-neutral-200)', fontSize: 'var(--font-size-lg)', fontWeight: 600 }}>
            {title}
          </div>
        )}
        <div style={{ padding: 'var(--spacing-4)', overflow: 'auto', flex: 1 }}>{children}</div>
        {footer && (
          <div style={{ padding: 'var(--spacing-4)', borderTop: '1px solid var(--color-neutral-200)', display: 'flex', justifyContent: 'flex-end', gap: 'var(--spacing-2)' }}>
            {footer}
          </div>
        )}
        {!footer && (
          <div style={{ padding: 'var(--spacing-4)', borderTop: '1px solid var(--color-neutral-200)', textAlign: 'right' }}>
            <Button variant="secondary" onClick={onClose}>Close</Button>
          </div>
        )}
      </div>
    </div>
  );
};
